var usr = 'Firma: ' + d.companyName + '. Obor: ' + (d.industry || 'obecny') + '. Cil webu: ' + d.goal + '. Ton komunikace: ' + d.tone + '. Sluzby: ' + d.servicesJson + '.';
var body = JSON.stringify({ model: 'gpt-4o-mini', response_format: { type: 'json_object' }, messages: [{ role: 'system', content: sys }, { role: 'user', content: usr }], temperature: 0.7, max_tokens: 1200 });
return [{ json: { companyName: d.companyName, email: d.email, phone: d.phone, goal: d.goal, tone: d.tone, industry: d.industry, slug: d.slug, repoName: d.repoName, services: services, openaiBody: body } }];

var q = String.fromCharCode(34);
var form = $('Code — Sestavit OpenAI request').first().json;
var aiRaw = $json.choices[0].message.content;
var ai;
try { ai = JSON.parse(aiRaw); } catch(e) {
  ai = { headline: form.companyName, subheadline: 'Profesionalni sluzby pro vase zakazniky.', cta_text: 'Kontaktujte nas', about: 'Jsme spolehliwa firma s dlouholetou tradici v oboru.', services_text: 'Nabizime kvalitni reseni prizpusobena vasim potrebam.', faq: [{ question: 'Jak vas mohu kontaktovat?', answer: 'Zavolejte nam nebo napiste email, odpovidame do 24 hodin.' }, { question: 'Kde pusobite?', answer: 'Pusobime po cele Ceske republice.' }, { question: 'Jak rychle praci realizujete?', answer: 'Standardni zakazku realizujeme do 2-3 tydnu.' }], footer_tagline: 'Vas spolehlivy partner.' };
}
var c = form.companyName, email = form.email, phone = form.phone, slug = form.slug, rn = form.repoName;
var services = Array.isArray(form.services) ? form.services : [];
var faqItems = Array.isArray(ai.faq) ? ai.faq : [];
var year = String(new Date().getFullYear());
var css = '*{margin:0;padding:0;box-sizing:border-box}body{font-family:system-ui,-apple-system,sans-serif;color:#111827;line-height:1.6}a{text-decoration:none;color:inherit}.container{max-width:1100px;margin:0 auto;padding:0 1.5rem}nav{position:sticky;top:0;z-index:99;background:#fff;border-bottom:1px solid #f3f4f6;padding:.75rem 0}.nav-inner{display:flex;align-items:center;justify-content:space-between}.nav-logo{font-weight:900;font-size:1.1rem}.nav-cta{background:#22c55e;color:#fff;padding:.5rem 1.25rem;border-radius:9999px;font-weight:600;font-size:.9rem;transition:.2s}.nav-cta:hover{background:#16a34a}.hero{padding:6rem 1.5rem 4rem;text-align:center;background:linear-gradient(135deg,#f0fdf4 0%,#fff 60%)}.hero-tag{color:#16a34a;font-size:.75rem;letter-spacing:.15em;text-transform:uppercase;font-weight:600;margin-bottom:1.2rem}h1{font-size:clamp(2rem,5vw,3.5rem);font-weight:900;line-height:1.15;max-width:800px;margin:0 auto 1.5rem}.hero-sub{font-size:1.1rem;color:#6b7280;max-width:560px;margin:0 auto 2.5rem}.btn{display:inline-block;background:#22c55e;color:#fff;font-weight:700;font-size:1.05rem;padding:1rem 2.5rem;border-radius:9999px;transition:.2s}.btn:hover{background:#16a34a}section{padding:5rem 1.5rem}h2{font-size:1.9rem;font-weight:900;text-align:center;margin-bottom:.75rem}.sec-sub{color:#6b7280;text-align:center;max-width:540px;margin:0 auto 3rem}.svc-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:1.5rem;max-width:960px;margin:0 auto}.svc-card{background:#f9fafb;border:1px solid #e5e7eb;border-radius:1rem;padding:1.5rem;transition:.2s}.svc-card:hover{border-color:#22c55e}.svc-icon{width:2.5rem;height:2.5rem;background:#dcfce7;border-radius:.75rem;display:flex;align-items:center;justify-content:center;margin-bottom:1rem;font-size:1.1rem}.svc-name{font-weight:700;font-size:.95rem}.about-sec{background:#f9fafb}.about-in{max-width:700px;margin:0 auto;text-align:center}.about-in p{color:#6b7280;line-height:1.85}.faq-list{max-width:700px;margin:0 auto}.faq-item{border-bottom:1px solid #e5e7eb}.faq-btn{width:100%;background:none;border:none;text-align:left;padding:1.2rem 0;font-size:1rem;font-weight:600;cursor:pointer;display:flex;justify-content:space-between;align-items:center;color:#111}.faq-ico{color:#22c55e;font-size:1.3rem;transition:.3s;display:inline-block;line-height:1}.faq-btn.open .faq-ico{transform:rotate(45deg)}.faq-ans{max-height:0;overflow:hidden;transition:.3s;color:#6b7280;line-height:1.75;font-size:.95rem}.faq-ans.open{max-height:300px;padding-bottom:1.2rem}.contact-sec{background:linear-gradient(135deg,#f0fdf4,#fff);text-align:center}.contact-box{max-width:460px;margin:0 auto}.contact-phone{font-size:2rem;font-weight:900;color:#22c55e;margin:1.5rem 0 .5rem}.contact-email{color:#6b7280}footer{padding:2rem 1.5rem;border-top:1px solid #f3f4f6;text-align:center;font-size:.85rem;color:#9ca3af}footer a{color:#22c55e}';
var svcs = services.map(function(s){ return '<div class=' + q + 'svc-card' + q + '><div class=' + q + 'svc-icon' + q + '>&#10003;</div><p class=' + q + 'svc-name' + q + '>' + s + '</p></div>'; }).join('');
if(!svcs) svcs = '<div class=' + q + 'svc-card' + q + '><div class=' + q + 'svc-icon' + q + '>&#10003;</div><p class=' + q + 'svc-name' + q + '>Odborne sluzby</p></div>';
var faqHtml = faqItems.map(function(f){ return '<div class=' + q + 'faq-item' + q + '><button class=' + q + 'faq-btn' + q + ' onclick=' + q + 'tFaq(this)' + q + '>' + f.question + ' <span class=' + q + 'faq-ico' + q + '>+</span></button><div class=' + q + 'faq-ans' + q + '>' + f.answer + '</div></div>'; }).join('');
if(!faqHtml) faqHtml = '<p>Kontaktujte nas s jakymkoliv dotazem.</p>';
var html = '<!DOCTYPE html><html lang=' + q + 'cs' + q + '><head><meta charset=' + q + 'UTF-8' + q + '><meta name=' + q + 'viewport' + q + ' content=' + q + 'width=device-width,initial-scale=1.0' + q + '><title>' + c + '</title><link rel=' + q + 'stylesheet' + q + ' href=' + q + 'style.css' + q + '></head><body>';
html += '<nav><div class=' + q + 'container nav-inner' + q + '><span class=' + q + 'nav-logo' + q + '>' + c + '</span><a href=' + q + '#kontakt' + q + ' class=' + q + 'nav-cta js-scroll' + q + '>' + ai.cta_text + '</a></div></nav>';
html += '<section class=' + q + 'hero' + q + '><p class=' + q + 'hero-tag' + q + '>' + c + '</p><h1>' + ai.headline + '</h1><p class=' + q + 'hero-sub' + q + '>' + ai.subheadline + '</p><a href=' + q + '#kontakt' + q + ' class=' + q + 'btn js-scroll' + q + '>' + ai.cta_text + '</a></section>';
html += '<section><div class=' + q + 'container' + q + '><h2>Co nabizime</h2><p class=' + q + 'sec-sub' + q + '>' + ai.services_text + '</p><div class=' + q + 'svc-grid' + q + '>' + svcs + '</div></div></section>';
html += '<section class=' + q + 'about-sec' + q + '><div class=' + q + 'container' + q + '><div class=' + q + 'about-in' + q + '><h2>O nas</h2><p>' + ai.about + '</p></div></div></section>';
html += '<section><div class=' + q + 'container' + q + '><h2>Caste dotazy</h2><div class=' + q + 'faq-list' + q + '>' + faqHtml + '</div></div></section>';
html += '<section class=' + q + 'contact-sec' + q + ' id=' + q + 'kontakt' + q + '><div class=' + q + 'contact-box' + q + '><h2>Kontaktujte nas</h2><p class=' + q + 'contact-phone' + q + '>' + phone + '</p><p class=' + q + 'contact-email' + q + '>' + email + '</p></div></section>';
html += '<footer><div class=' + q + 'container' + q + '><p>&#169; ' + year + ' ' + c + '. ' + ai.footer_tagline + '</p><p>Web vytvorěn přes <a href=' + q + 'https://webdo24.cz' + q + '>webdo24.cz</a></p></div></footer>';
html += '<script src=' + q + 'script.js' + q + '></script></body></html>';
var js = 'function tFaq(btn){var a=btn.nextElementSibling,o=a.classList.contains(' + q + 'open' + q + ');document.querySelectorAll(' + q + '.faq-btn' + q + ').forEach(function(b){b.classList.remove(' + q + 'open' + q + ')});document.querySelectorAll(' + q + '.faq-ans' + q + ').forEach(function(b){b.classList.remove(' + q + 'open' + q + ')});if(!o){btn.classList.add(' + q + 'open' + q + ');a.classList.add(' + q + 'open' + q + ');}}';
js += 'document.querySelectorAll(' + q + '.js-scroll' + q + ').forEach(function(el){el.addEventListener(' + q + 'click' + q + ',function(e){e.preventDefault();var t=document.querySelector(this.getAttribute(' + q + 'href' + q + '));if(t)t.scrollIntoView({behavior:' + q + 'smooth' + q + ',block:' + q + 'start' + q + '});});});';
var vc = JSON.stringify({ version: 2 });
var db = JSON.stringify({ name: rn, files: [{ file: 'index.html', data: html, encoding: 'utf-8' }, { file: 'style.css', data: css, encoding: 'utf-8' }, { file: 'script.js', data: js, encoding: 'utf-8' }, { file: 'vercel.json', data: vc, encoding: 'utf-8' }], target: 'production', projectSettings: { framework: null } });
return [{ json: { companyName: c, email: email, phone: phone, slug: slug, repoName: rn, htmlBase64: Buffer.from(html).toString('base64'), cssBase64: Buffer.from(css).toString('base64'), jsBase64: Buffer.from(js).toString('base64'), vercelJsonBase64: Buffer.from(vc).toString('base64'), deployBody: db, siteUrl: 'https://' + rn + '.vercel.app' } }];
